package com.yottastudios.ns.collabspace.shared.config;

import org.springframework.amqp.core.*;
import com.yottastudios.ns.collabspace.shared.config.properties.NextcloudProperties;
import org.springframework.amqp.rabbit.config.SimpleRabbitListenerContainerFactory;
import org.springframework.amqp.rabbit.connection.ConnectionFactory;
import org.springframework.boot.SpringBootConfiguration;
import org.springframework.context.annotation.Bean;
import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty;

import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

@SpringBootConfiguration
@ConditionalOnProperty(name = "mq.enabled", havingValue = "true", matchIfMissing = true)
public class QueueConfig {

    public static final String APITABLE_USER_ADMIN_CHANGE_QUEUE = "apitable.consumer.user.admin_change.queue";
    public static final String APITABLE_USER_SPACE_CHANGE_QUEUE = "apitable.consumer.user.space_change.queue";
    public static final String APITABLE_NODE_CREATE_QUEUE = "apitable.consumer.node.create.queue";
    public static final String APITABLE_UNIT_MEMBERSHIP_CHANGE_QUEUE = "apitable.consumer.permission.unit_membership_change.queue";
    public static final String  AIO_TEAM_OPERATE_QUEUE= "aio.team.operate.queue";
    public static final String SPACE_NODE_MIGRATION_QUEUE = "space.node.migration.queue";
    public static final String ANNOUNCEMENT_QUEUE = "announcement.queue";
    public static final String THIRD_APP_UPLOAD_UPDATE_QUEUE = "third.app.upload.update.queue";

    public static final String APITABLE_USER_ADMIN_CHANGE_ROUTING_KEY = "apitable.event.notification.user_admin_change";
    public static final String APITABLE_USER_SPACE_CHANGE_ROUTING_KEY = "apitable.event.notification.user_space_change";
    public static final String APITABLE_NODE_CREATE_ROUTING_KEY = "apitable.event.notification.node_create";
    public static final String APITABLE_UNIT_MEMBERSHIP_CHANGE_ROUTING_KEY = "apitable.event.notification.unit_membership_change";
    public static final String AIO_TEAM_OPERATE_KEY = "aio.team.operate.key";
    public static final String SPACE_NODE_MIGRATION_KEY = "space.node.migration.key";
    public static final String ANNOUNCEMENT_KEY = "announcement.key";
    public static final String THIRD_APP_UPLOAD_UPDATE_ROUTING_KEY = "third.app.upload.update.key";
    public static final String TEST_ROUTING_KEY = "collabspace.event.notification.test";

    public static final String COLLABSPACE_EVENT_NOTIFICATION_EXCHANGE = "collabspace.event.notification.exchange";
    public static final String APITABLE_EVENT_NOTIFICATION_EXCHANGE = "apitable.event.notification.exchange";
    public static final String AIO_TEAM_OPERATE_EXCHANGE = "aio.team.operate.exchange";
    public static final String SPACE_NODE_MIGRATION_EXCHANGE = "space.node.migration.exchange";
    public static final String ANNOUNCEMENT_EXCHANGE = "announcement.exchange";
    public static final String THIRD_APP_UPLOAD_UPDATE_EXCHANGE = "third.app.upload.update.exchange";

    // ── Nextcloud Webhook 分片队列 ──
    public static final String NEXTCLOUD_WEBHOOK_DIRECT_EXCHANGE = "nextcloud.webhook.direct.exchange";
    public static final String NEXTCLOUD_WEBHOOK_SHARD_QUEUE_PREFIX = "nextcloud.webhook.shard.queue.";
    public static final String NEXTCLOUD_WEBHOOK_SHARD_ROUTING_KEY_PREFIX = "nextcloud.webhook.shard.";
    public static final int NEXTCLOUD_WEBHOOK_SHARD_COUNT = 4;

    public static final String NEXTCLOUD_WEBHOOK_SHARD_QUEUE_0 = NEXTCLOUD_WEBHOOK_SHARD_QUEUE_PREFIX + "0";
    public static final String NEXTCLOUD_WEBHOOK_SHARD_QUEUE_1 = NEXTCLOUD_WEBHOOK_SHARD_QUEUE_PREFIX + "1";
    public static final String NEXTCLOUD_WEBHOOK_SHARD_QUEUE_2 = NEXTCLOUD_WEBHOOK_SHARD_QUEUE_PREFIX + "2";
    public static final String NEXTCLOUD_WEBHOOK_SHARD_QUEUE_3 = NEXTCLOUD_WEBHOOK_SHARD_QUEUE_PREFIX + "3";

    // ── collabspace doc change (广播给 rag-doc-server) ──
    public static final String COLLABSPACE_DOC_CHANGE_EXCHANGE = "collabspace.doc.change.exchange";
    public static final String COLLABSPACE_DOC_CHANGE_KEY = "collabspace.doc.change.key";

    // ── collabspace doc delete (通知 rag-doc-server 删除文档) ──
    public static final String COLLABSPACE_DOC_DELETE_EXCHANGE = "collabspace.doc.delete.exchange";
    public static final String COLLABSPACE_DOC_DELETE_KEY = "collabspace.doc.delete.key";

    // ── collabspace permission sync (权限同步给 rag-doc-server) ──
    public static final String COLLABSPACE_PERMISSION_SYNC_EXCHANGE = "collabspace.permission.sync.exchange";
    public static final String COLLABSPACE_PERMISSION_SYNC_KEY = "collabspace.permission.sync.key";

    @Bean
    public Queue userAdminChangeQueue() {
        return new Queue(APITABLE_USER_ADMIN_CHANGE_QUEUE);
    }

    @Bean
    public Queue userSpaceChangeQueue() {
        return new Queue(APITABLE_USER_SPACE_CHANGE_QUEUE);
    }

    @Bean
    public Queue nodeCreateQueue() {
        return new Queue(APITABLE_NODE_CREATE_QUEUE);
    }

    @Bean
    public Queue unitMembershipChangeQueue() {
        return new Queue(APITABLE_UNIT_MEMBERSHIP_CHANGE_QUEUE);
    }

    @Bean
    public Queue aioTeamOperateQueue() {
        return new Queue(AIO_TEAM_OPERATE_QUEUE);
    }

    @Bean
    public Queue spaceNodeMigrationQueue() {
        return new Queue(SPACE_NODE_MIGRATION_QUEUE);
    }

    @Bean
    public TopicExchange apitableEventNotificationExchange() {
        return new TopicExchange(APITABLE_EVENT_NOTIFICATION_EXCHANGE);
    }

    @Bean
    public TopicExchange collabspaceEventNotificationExchange() {
        return new TopicExchange(COLLABSPACE_EVENT_NOTIFICATION_EXCHANGE);
    }

    @Bean
    DirectExchange aioTeamOperateExchange() {
        return new DirectExchange(AIO_TEAM_OPERATE_EXCHANGE);
    }

    @Bean
    DirectExchange spaceNodeMigrationExchange() {
        return new DirectExchange(SPACE_NODE_MIGRATION_EXCHANGE);
    }



    @Bean
    public Queue announcementQueue() {
        return QueueBuilder.durable(ANNOUNCEMENT_QUEUE).build();
    }

    @Bean
    public Queue thirdAppUploadUpdateQueue() {
        return QueueBuilder.durable(THIRD_APP_UPLOAD_UPDATE_QUEUE).build();
    }

    @Bean
    public CustomExchange announcementExchange() {
        Map<String, Object> args = new HashMap<>();
        args.put("x-delayed-type", "direct");  // 在交换机声明时指定 x-delayed-type
        return new CustomExchange(ANNOUNCEMENT_EXCHANGE, "x-delayed-message", true, false, args);
    }

    @Bean
    public DirectExchange thirdAppUploadUpdateExchange() {
        return new DirectExchange(THIRD_APP_UPLOAD_UPDATE_EXCHANGE);
    }



    @Bean
    DirectExchange nextcloudWebhookDirectExchange() {
        return new DirectExchange(NEXTCLOUD_WEBHOOK_DIRECT_EXCHANGE);
    }

    @Bean
    public Declarables nextcloudWebhookShardDeclarables() {
        DirectExchange exchange = new DirectExchange(NEXTCLOUD_WEBHOOK_DIRECT_EXCHANGE);
        List<Declarable> items = new ArrayList<>();
        for (int i = 0; i < NEXTCLOUD_WEBHOOK_SHARD_COUNT; i++) {
            Queue queue = QueueBuilder.durable(NEXTCLOUD_WEBHOOK_SHARD_QUEUE_PREFIX + i).build();
            String routingKey = NEXTCLOUD_WEBHOOK_SHARD_ROUTING_KEY_PREFIX + i;
            items.add(queue);
            items.add(BindingBuilder.bind(queue).to(exchange).with(routingKey));
        }
        return new Declarables(items);
    }

    /**
     * Nextcloud 分片消费专用 ContainerFactory：
     * 使用批量回调 + AUTO ACK（监听方法成功返回后 ack，抛异常后 reject 且不 requeue）。
     * 通过 receiveTimeout 控制 2s 收包窗口，同 shard 单消费者保证顺序。
     */
    @Bean
    public SimpleRabbitListenerContainerFactory nextcloudShardBatchContainerFactory(ConnectionFactory connectionFactory,
                                                                                    NextcloudProperties nextcloudProperties) {
        NextcloudProperties.Callback callback = nextcloudProperties.getCallback();
        int batchMaxSize = Math.max(callback.getBatchMaxSize(), 1);
        long receiveTimeoutMs = Math.max(callback.getBatchReceiveTimeoutMs(), 1);
        int concurrency = Math.max(callback.getConsumerConcurrencyPerShard(), 1);

        SimpleRabbitListenerContainerFactory factory = new SimpleRabbitListenerContainerFactory();
        factory.setConnectionFactory(connectionFactory);
        factory.setConcurrentConsumers(concurrency);
        factory.setMaxConcurrentConsumers(concurrency);
        factory.setBatchListener(true);
        factory.setConsumerBatchEnabled(true);
        factory.setBatchSize(batchMaxSize);
        factory.setPrefetchCount(batchMaxSize);
        factory.setReceiveTimeout(receiveTimeoutMs);
        factory.setAcknowledgeMode(AcknowledgeMode.AUTO);
        factory.setDefaultRequeueRejected(false);
        return factory;
    }

    @Bean
    public DirectExchange collabspaceDocChangeExchange() {
        return new DirectExchange(COLLABSPACE_DOC_CHANGE_EXCHANGE);
    }

    @Bean
    public DirectExchange collabspaceDocDeleteExchange() {
        return new DirectExchange(COLLABSPACE_DOC_DELETE_EXCHANGE);
    }

    @Bean
    DirectExchange collabspacePermissionSyncExchange() {
        return new DirectExchange(COLLABSPACE_PERMISSION_SYNC_EXCHANGE);
    }

    @Bean
    public Declarables bindings() {
        return new Declarables(
                BindingBuilder.bind(userAdminChangeQueue()).to(apitableEventNotificationExchange()).with(APITABLE_USER_ADMIN_CHANGE_ROUTING_KEY),
                BindingBuilder.bind(userSpaceChangeQueue()).to(apitableEventNotificationExchange()).with(APITABLE_USER_SPACE_CHANGE_ROUTING_KEY),
                BindingBuilder.bind(nodeCreateQueue()).to(apitableEventNotificationExchange()).with(APITABLE_NODE_CREATE_ROUTING_KEY),
                BindingBuilder.bind(unitMembershipChangeQueue()).to(apitableEventNotificationExchange()).with(APITABLE_UNIT_MEMBERSHIP_CHANGE_ROUTING_KEY),
                BindingBuilder.bind(aioTeamOperateQueue()).to(aioTeamOperateExchange()).with(AIO_TEAM_OPERATE_KEY),
                BindingBuilder.bind(spaceNodeMigrationQueue()).to(spaceNodeMigrationExchange()).with(SPACE_NODE_MIGRATION_KEY),
                BindingBuilder.bind(announcementQueue()).to(announcementExchange()).with(ANNOUNCEMENT_KEY).noargs(),
                BindingBuilder.bind(thirdAppUploadUpdateQueue()).to(thirdAppUploadUpdateExchange()).with(THIRD_APP_UPLOAD_UPDATE_ROUTING_KEY)

        );
    }

}

