 96→    abstract static class TreeNodeMixin<T extends RelIdProvider> {
 97→        @JsonProperty("children")
 98→        @JsonDeserialize(contentAs = TreeNode.class)
 99→        abstract List<TreeNode<T>> getChildren();
100→
101→        @JsonProperty("children")
102→        abstract void setChildren(List<TreeNode<T>> children);
103→    }
