105→    @RabbitListener(queues = SPACE_NODE_MIGRATION_QUEUE)
106→    public void handle(Message message, Channel channel) throws IOException {
107→        String body = new String(message.getBody());
108→        log.info("Received space node migration task message: {}", body);
109→
110→        SpaceNodeMigrationMessage messageDto = JSONUtil.toBean(body, SpaceNodeMigrationMessage.class);
111→        String taskId = messageDto.getTaskId();
112→
113→        try {
114→            SpaceNodeMigrationTaskEntity task = spaceNodeMigrationTaskService.getByTaskId(taskId);
115→            ExceptionUtil.isNotNull(task, DatabaseException.QUERY_EMPTY_BY_ID);
116→            task.setStatus(SpaceNodeMigrationTaskStatusEnum.PROCESSING.getValue());
117→            spaceNodeMigrationTaskService.updateById(task);
118→
119→            executeTask(task);
120→
121→            task.setStatus(SpaceNodeMigrationTaskStatusEnum.COMPLETED.getValue());
122→            spaceNodeMigrationTaskService.updateById(task);
123→
124→        } catch (Exception e) {
125→            log.error("Failed to process space node migration task: taskId={}, error={}", taskId, e.getMessage(), e);
126→            SpaceNodeMigrationTaskEntity task = spaceNodeMigrationTaskService.getByTaskId(taskId);
127→            if (task != null) {
128→                task.setStatus(SpaceNodeMigrationTaskStatusEnum.FAILED.getValue());
129→                task.setErrorMessage(e.getMessage());
130→                spaceNodeMigrationTaskService.updateById(task);
131→            }
132→        } finally {
133→            // 先不考虑重试
134→            long deliveryTag = message.getMessageProperties().getDeliveryTag();
135→            channel.basicAck(deliveryTag, false);
136→        }
137→    }
138→
139→    private void executeTask(SpaceNodeMigrationTaskEntity task) throws IOException {
140→        UserSimpleInfoVo user = apitableGrpcClientService.getUserByEmail(task.getEmail());
141→        ExceptionUtil.isNotNull(user, SpaceNodeMigrationException.OPERATOR_NOT_EXIST);
142→        Long userId = user.getId();
143→        // 鉴权
144→        if (!spaceQueryManager.isUserSpaceAdmin(userId, task.getTargetSpaceId())) {
145→            throw new BusinessException(AuthException.UNAUTHORIZED);
146→        }
147→
148→        List<TreeNode<SpaceNodeVo>> spaceNodeTree = deserializeTree(task.getOriginTree());
149→        List<SpaceAppRelVo> sourceSpaceAppRels = JSONUtil.toList(task.getSourceSpaceAppRels(), SpaceAppRelVo.class);
150→        MigrationTypeEnum migrationType = MigrationTypeEnum.fromValue(task.getType());
151→
152→        log.info("executeTask: taskId={}, treeSize={}, type: {}, targetParentNodeId={}, appRels: {}",
153→                task.getTaskId(), spaceNodeTree.size(), migrationType.getDescription(), task.getTargetParentNodeId(), task.getSourceSpaceAppRels());
154→
155→        MigrationConfig migrationConfig = MigrationConfig.builder()
156→                .email(task.getEmail())
157→                .sourceSpaceAppRels(sourceSpaceAppRels)
158→                .build();
159→        
160→        SpaceNodeMigrationResult overallResult = appMigrationChain.executeMigration(
161→                spaceNodeTree, 
162→                task.getTargetSpaceId(),
163→                task.getSourceSpaceId(),
164→                migrationType, 
165→                migrationConfig
166→        );
167→        
168→        log.info("Overall migration completed: success={}, failed={}, total mappings={}", 
169→                overallResult.getSuccessCount(), overallResult.getFailedCount(), 
170→                overallResult.getNodeIdMapping().size());
171→
172→        // 迁移中遇到错误抛异常并终止迁移
173→        if (overallResult.getErrorMessage() != null) {
174→            log.warn("Migration had errors: {}", overallResult.getErrorMessage());
175→            throw new BusinessException(overallResult.getErrorMessage());
176→        }
177→
178→        // 迁移后的节点重新构建成树并入库
179→        // targetParentNodeId 是 space_node 表的 ID，需转换为 node 表的 ID 作为树的 parentId
180→        Long rootParentId = ROOT_PARENT_ID;
181→        if (task.getTargetParentNodeId() != null) {
182→            // 校验 targetParentNodeId 归属目标空间站且为文件夹类型
183→            SpaceNodeEntity targetSpaceNode = spaceNodeService.getById(task.getTargetParentNodeId());
184→            if (targetSpaceNode == null) {
185→                log.warn("[lbl][2263-mirror-copy][Migration][VALIDATE] targetParentNodeId={} 不存在，使用根目录", task.getTargetParentNodeId());
186→            } else if (!Objects.equals(targetSpaceNode.getSpaceId(), task.getTargetSpaceId())) {
187→                log.warn("[lbl][2263-mirror-copy][Migration][VALIDATE] targetParentNodeId={} 不属于目标空间站 targetSpaceId={}，实际 spaceId={}，使用根目录",
188→                        task.getTargetParentNodeId(), task.getTargetSpaceId(), targetSpaceNode.getSpaceId());
189→            } else if (!Objects.equals(targetSpaceNode.getType(), SpaceNodeTypeEnum.FOLDER.getValue())) {
190→                log.warn("[lbl][2263-mirror-copy][Migration][VALIDATE] targetParentNodeId={} 不是文件夹类型 type={}，使用根目录",
191→                        task.getTargetParentNodeId(), targetSpaceNode.getType());
192→            } else {
193→                NodeEntity parentNode = nodeService.getByRelId(task.getTargetParentNodeId());
194→                if (parentNode != null) {
195→                    rootParentId = parentNode.getId();
196→                } else {
197→                    log.warn("[lbl][2263-mirror-copy][Migration][VALIDATE] targetParentNodeId={} 对应的 node 不存在，使用根目录", task.getTargetParentNodeId());
198→                }
199→            }
200→        }
201→        saveNewNodeTree(spaceNodeTree, task.getTargetSpaceId(), overallResult.getNodeIdMapping(), userId,
202→                task.getSourceSpaceId(), migrationType, migrationConfig, rootParentId);
203→        // 判断是空间站内迁移并且保留状态是false，调用文件删除接口，把源文件删除
204→        if (!task.getIsRemained() && task.getType().equals(MigrationTypeEnum.INTRA_SERVER.getValue())) {
205→            log.info("[lbl][2122-文件迁移][Migration][DELETE] 移动模式, 开始清理源文件及快照, taskId={}, sourceSpaceId={}, nodeCount={}",
206→                    task.getTaskId(), task.getSourceSpaceId(), spaceNodeTree.size());
207→            for (TreeNode<SpaceNodeVo> treeNode : spaceNodeTree) {
208→                // 清理源文件的版本快照
209→                versionSnapshotService.disableByNodeId(treeNode.getRelId());
210→                spaceNodeUpdateManager.deleteSpaceNode(treeNode.getRelId(), userId);
211→            }
212→        }
213→    }
214→
215→    private void saveNewNodeTree(List<TreeNode<SpaceNodeVo>> originalTree, String spaceId, Map<String, String> nodeIdMapping,
216→                                  Long userId, String sourceSpaceId, MigrationTypeEnum migrationType, MigrationConfig migrationConfig, Long rootParentId) {
217→        if (originalTree == null || originalTree.isEmpty()) {
218→            log.info("No tree nodes to save for space: {}", spaceId);
219→            return;
220→        }
221→
222→        log.info("Starting to save new node tree for space: {}, rootParentId: {}, total original nodes: {}", spaceId, rootParentId, originalTree.size());
223→
224→        for (TreeNode<SpaceNodeVo> node : originalTree) {
225→            saveNodeAndChildren(node, spaceId, nodeIdMapping, rootParentId, userId,
226→                    sourceSpaceId, migrationType, migrationConfig);
227→        }
228→
229→        log.info("Completed saving new node tree for space: {}", spaceId);
230→    }
231→
232→    private String resolveUniqueName(String spaceId, String name, Long parentId) {
233→        if (spaceNodeQueryManager.checkNameWithParentOnly(spaceId, name, parentId)) {
234→            return name;
235→        }
236→        int count = 1;
237→        while (true) {
238→            String candidate = name + "(" + count + ")";
239→            if (spaceNodeQueryManager.checkNameWithParentOnly(spaceId, candidate, parentId)) {
240→                return candidate;
241→            }
242→            count++;
243→        }
244→    }
245→
246→    private void saveNodeAndChildren(TreeNode<SpaceNodeVo> node, String spaceId, Map<String, String> nodeIdMapping,
247→                                      Long parentId, Long userId, String sourceSpaceId,
248→                                      MigrationTypeEnum migrationType, MigrationConfig migrationConfig) {
249→        SpaceNodeVo spaceNodeVo = node.getData();
250→        String oldNodeId = spaceNodeVo.getAppSpaceNodeId();
251→        String newNodeId = nodeIdMapping.get(oldNodeId);
252→
253→        if (Objects.equals(spaceNodeVo.getType(), SpaceNodeTypeEnum.FOLDER.getValue())) {
254→            newNodeId = "";
255→        }
256→
257→        if (newNodeId == null) {
258→            log.error("No mapping found for node: {}", oldNodeId);
259→            return;
260→        }
261→
262→        String originalName = spaceNodeVo.getName();
263→        String name = MigrationTypeEnum.CROSS_SERVER.equals(migrationType)
264→                ? resolveUniqueName(spaceId, originalName, parentId)
265→                : originalName;
266→        if (!name.equals(originalName)) {
267→            log.info("[2010-change-filename] migrate node name conflict, renamed: [{}] -> [{}], spaceId: {}, " +
268→                            "parentId: {}",
269→                    originalName,
270→                    name, spaceId, parentId);
271→        }
272→
273→        SpaceNodeEntity spaceNodeEntity = SpaceNodeEntity.builder()
274→                .appSpaceNodeId(newNodeId)
275→                .name(name)
276→                .type(spaceNodeVo.getType())
277→                .description(spaceNodeVo.getDescription())
278→                .spaceId(spaceId)
279→                .createdBy(userId)
280→                .updatedBy(userId)
281→                .build();
282→
283→        spaceNodeService.save(spaceNodeEntity);
284→        NodeEntity nodeEntity = treeNodeTemplate.addNode(parentId, spaceId, spaceNodeEntity.getId(), SpaceNodeEntity.class);
285→        log.info("migrate node, id: {}, appSpaceNodeId: {}, name: {}, parentId",spaceNodeEntity.getId(),spaceNodeEntity.getAppSpaceNodeId(),spaceNodeEntity.getName());
286→
287→        // 复制文件关联的版本快照
288→        versionSnapshotMigrationHelper.copyVersionSnapshots(node.getRelId(), spaceNodeEntity, spaceId, sourceSpaceId, migrationType, migrationConfig, userId);
289→
290→        if (node.getChildren() != null && !node.getChildren().isEmpty()) {
291→            for (TreeNode<SpaceNodeVo> child : node.getChildren()) {
292→                saveNodeAndChildren(child, spaceId, nodeIdMapping, nodeEntity.getId(), userId,
293→                        sourceSpaceId, migrationType, migrationConfig);
294→            }
295→        }
296→    }
297→
298→
299→    private List<TreeNode<SpaceNodeVo>> deserializeTree(String json) throws IOException {
300→        ObjectMapper mapper = objectMapper.copy();
301→        mapper.addMixIn(TreeNode.class, TreeNodeMixin.class);
302→        SimpleModule module = new SimpleModule();
303→        module.addAbstractTypeMapping(RelIdProvider.class, SpaceNodeVo.class);
304→        mapper.registerModule(module);
305→        JavaType treeNodeType =
306→                mapper.getTypeFactory().constructParametricType(TreeNode.class, SpaceNodeVo.class);
307→        JavaType listType =
308→                mapper.getTypeFactory().constructCollectionType(List.class, treeNodeType);
309→        return mapper.readValue(json, listType);
310→    }
311→
312→}

