@Override
public void uploadUpdateTime(String params) {
    log.info("接收到更新参数{}", params);
    if (mqEnabled) {
        thirdAppUploadUpdateAsyncService.enqueueWithDedup(params);
        return;
    }
    doUploadUpdateTime(params);
}

public void doUploadUpdateTime(String params) {
    ThirdAppUploadUpdateParam param = JSON.parseObject(params, ThirdAppUploadUpdateParam.class);
    log.info("json解析后的参数{}", param);
    String appId = param == null ? null : param.getAppId();
    String updateTime = param == null ? null : param.getUpdateTime();

    if (appId == null || updateTime == null || appId.isBlank() || updateTime.isBlank()) {
        throw new BusinessException("Missing appId and updateTime parameter");
    }

    LocalDateTime updateDateTime = parseDateTime(updateTime);

    // 根据appId获取到对应的node数据
    List<SpaceNodeEntity> spaceNodeEntityList = iSpaceNodeService.listByAppSpaceNodeIds(List.of(appId));
    // 根据node数据获取父node数据
    List<NodeEntity> nodeEntityList = treeNodeTemplate.getParentPathNodesByRelIds(spaceNodeEntityList.stream().
            map(SpaceNodeEntity::getId).collect(Collectors.toList()));
    List<Long> allRelNodeEntityIds = nodeEntityList.stream().map(NodeEntity::getRelId).toList();
    // 获取space
    List<SpaceNodeEntity> allSpaceNodeEntityList = iSpaceNodeService.listByIdsIncludeDeleted(allRelNodeEntityIds);
    allSpaceNodeEntityList.forEach(spaceNodeEntity -> {
        spaceNodeEntity.setUpdatedAt(updateDateTime);
        spaceNodeMapper.updateNodeTime(spaceNodeEntity.getId(), updateDateTime);
    });
    List<SpaceNodeForWebSocketVo> voList = allSpaceNodeEntityList.stream()
            .map(SpaceNodeForWebSocketVo::from)
            .toList();

    WebSocketResponseModel webSocketResponseModel = WebSocketResponseModel.builder().type(MessageTypeEnum.UPDATE_FILE_TIME.getType())
                    .message("更新时间").status(200).data(voList).build();
    String msg;
    try {
        msg = objectMapper.writeValueAsString(webSocketResponseModel);
    } catch (JsonProcessingException e) {
        throw new BusinessException("WebSocket序列化失败", e);
    }
    List<Long> spaceNodeIds = allSpaceNodeEntityList.stream().map(SpaceNodeEntity::getId).toList();
    List<Long> userIds = spaceNodeUserRoleCacheQueryManager.listUserIdsBySpaceNodeIdsAndMinRole(spaceNodeIds, NodeRoleLevel.READER);
    // 通知 rag-doc-server 重新索引变动的节点（与 WebSocket 推送无关，独立执行）
    if (ragDocNotifyPublisher != null) {
        for (SpaceNodeEntity spaceNode : spaceNodeEntityList) {
            ragDocNotifyPublisher.publishDocChange(spaceNode);
        }
    }

    if (userIds.isEmpty()) {
        log.warn("未找到相关节点权限用户，跳过WebSocket推送");
        return;

