import jakarta.annotation.Resource;
import lombok.extern.slf4j.Slf4j;
import org.springframework.amqp.core.Message;
import org.springframework.amqp.rabbit.annotation.RabbitListener;
import org.springframework.stereotype.Component;
import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty;

import java.io.IOException;
import java.time.LocalDateTime;

import static com.yottastudios.ns.collabspace.shared.config.QueueConfig.ANNOUNCEMENT_QUEUE;

@Slf4j
@Component
@ConditionalOnProperty(name = "mq.enabled", havingValue = "true", matchIfMissing = true)
public class AnnouncementConsumer {
    @Resource
    AnnouncementMapper announcementMapper;

    @Resource
    WebSocketHandler webSocketHandler;

    @Resource
    AnnouncementPushService announcementPushService;

    @RabbitListener(queues = ANNOUNCEMENT_QUEUE)
    public void handle(Message message, Channel channel) throws IOException {
        log.info("Received announcement message: {}", message);
        String body = new String(message.getBody());
        Long announcementId = Long.parseLong(body);
        try {
        AnnouncementEntity announce = announcementMapper.selectById(announcementId);
        if (announce == null || announce.getStatus() == AnnouncementStatus.CANCELLED.getCode()
        || announce.getType() == AnnouncementType.DRAFT.getCode()) {
            throw new RuntimeException("公告不需要发布");
        }
        announce.setStatus(AnnouncementStatus.PUBLISHED.getCode());
        announce.setUpdatedAt(LocalDateTime.now());
        announcementMapper.updateById(announce);

         WebSocketResponseModel webSocketResponseModel = WebSocketResponseModel.builder().type(MessageTypeEnum.ADD_ANNOUNCEMENT.getType())
                    .message("更新公告").status(200).data(null).build();
         String msg = JSONUtil.toJsonStr(webSocketResponseModel);
         webSocketHandler.sendAllUserToWebSocketClient(msg);

         // 同步推送到 Knock + MM
         announcementPushService.pushAnnouncement(announce);
        } catch (Exception e) {
            log.error("[lbl][2087-消息推送][Announcement][PUBLISH] 定时发布公告失败, id={}, error={}", announcementId, e.getMessage(), e);
        } finally {
            // 先不考虑重试
            long deliveryTag = message.getMessageProperties().getDeliveryTag();
            channel.basicAck(deliveryTag, false);
        }
    }
}

