package com.yottastudios.ns.collabspace.interfaces.eventbus.model;

import cn.hutool.core.util.BooleanUtil;
import cn.hutool.json.JSONUtil;
import com.rabbitmq.client.Channel;
import com.yottastudios.ns.collabspace.shared.holder.UserHolder;
import jakarta.annotation.Resource;
import lombok.extern.slf4j.Slf4j;
import org.slf4j.MDC;
import org.springframework.amqp.core.Message;
import org.springframework.data.redis.core.RedisTemplate;

import java.io.IOException;
import java.util.concurrent.TimeUnit;

import static com.yottastudios.ns.collabspace.shared.filter.MDCFilter.TRACE_ID;

@Slf4j
public abstract class BaseEventListener<T extends BaseEvent> {
    @Resource
    protected RedisTemplate<String, Object> redisTemplate;

    public void handleMessage(Message message, Channel channel, String queueName, Class<? extends BaseEvent> eventClass) throws IOException {
        long deliveryTag = message.getMessageProperties().getDeliveryTag();
        String body;

        try {
            UserHolder.init();
            body = new String(message.getBody());
            BaseEvent baseEvent = (BaseEvent) JSONUtil.toBean(body, eventClass);
            T event = (T) baseEvent;

            String traceId = event.getTraceId();
            MDC.put(TRACE_ID, traceId);

            log.info("收到消息: queue={}, eventType={}, body={}", queueName, event.getEventType(), body);

            if (isMessageDuplicate(queueName, traceId, deliveryTag)) {
                log.info("跳过重复消息: traceId={}", traceId);
                return;
            }
            Long userId = event.getOperatorId();
            if (userId == null) {
                log.warn("userId is null");
            }
            UserHolder.set(userId);
            handleEvent(event);
        } catch (Exception e) {
            log.error("[lbl][2417-MQ消费ACK-fixbug][EventBus][CONSUME] 处理消息异常, queue={}", queueName, e);
        } finally {
            try {
                channel.basicAck(deliveryTag, false);
            } catch (Exception e) {
                log.warn("[lbl][2417-MQ消费ACK-fixbug][EventBus][ACK] Channel已关闭, 无法ACK, queue={}, deliveryTag={}", queueName, deliveryTag, e);
            }
            UserHolder.remove();
            MDC.remove(TRACE_ID);
        }
    }

    protected boolean shouldRetry(Exception e) {
        // 默认不重试
        return false;
    }

    // 业务逻辑, 子类实现
    protected abstract void handleEvent(T event);

    private boolean isMessageDuplicate(String queue, String traceId, long deliveryTag) {
        String lockKey = queue + ":" + traceId + ":" + deliveryTag;
        Boolean lock = redisTemplate.opsForValue().setIfAbsent(lockKey, "1", 1, TimeUnit.DAYS);
        return BooleanUtil.isFalse(lock);
    }
}

