139→    private void executeTask(SpaceNodeMigrationTaskEntity task) throws IOException {
140→        UserSimpleInfoVo user = apitableGrpcClientService.getUserByEmail(task.getEmail());
141→        ExceptionUtil.isNotNull(user, SpaceNodeMigrationException.OPERATOR_NOT_EXIST);
142→        Long userId = user.getId();
143→        // 鉴权
144→        if (!spaceQueryManager.isUserSpaceAdmin(userId, task.getTargetSpaceId())) {
145→            throw new BusinessException(AuthException.UNAUTHORIZED);
146→        }
147→
148→        List<TreeNode<SpaceNodeVo>> spaceNodeTree = deserializeTree(task.getOriginTree());
149→        List<SpaceAppRelVo> sourceSpaceAppRels = JSONUtil.toList(task.getSourceSpaceAppRels(), SpaceAppRelVo.class);
150→        MigrationTypeEnum migrationType = MigrationTypeEnum.fromValue(task.getType());
151→
152→        log.info("executeTask: taskId={}, treeSize={}, type: {}, targetParentNodeId={}, appRels: {}",
153→                task.getTaskId(), spaceNodeTree.size(), migrationType.getDescription(), task.getTargetParentNodeId(), task.getSourceSpaceAppRels());
154→
155→        MigrationConfig migrationConfig = MigrationConfig.builder()
156→                .email(task.getEmail())
157→                .sourceSpaceAppRels(sourceSpaceAppRels)
158→                .build();
159→        
160→        SpaceNodeMigrationResult overallResult = appMigrationChain.executeMigration(
161→                spaceNodeTree, 
162→                task.getTargetSpaceId(),
163→                task.getSourceSpaceId(),
164→                migrationType, 
165→                migrationConfig
166→        );
167→        
168→        log.info("Overall migration completed: success={}, failed={}, total mappings={}", 
169→                overallResult.getSuccessCount(), overallResult.getFailedCount(), 
170→                overallResult.getNodeIdMapping().size());
171→
172→        // 迁移中遇到错误抛异常并终止迁移
173→        if (overallResult.getErrorMessage() != null) {
174→            log.warn("Migration had errors: {}", overallResult.getErrorMessage());
175→            throw new BusinessException(overallResult.getErrorMessage());
176→        }
177→
178→        // 迁移后的节点重新构建成树并入库
179→        // targetParentNodeId 是 space_node 表的 ID，需转换为 node 表的 ID 作为树的 parentId
180→        Long rootParentId = ROOT_PARENT_ID;
181→        if (task.getTargetParentNodeId() != null) {
182→            // 校验 targetParentNodeId 归属目标空间站且为文件夹类型
183→            SpaceNodeEntity targetSpaceNode = spaceNodeService.getById(task.getTargetParentNodeId());
184→            if (targetSpaceNode == null) {
185→                log.warn("[lbl][2263-mirror-copy][Migration][VALIDATE] targetParentNodeId={} 不存在，使用根目录", task.getTargetParentNodeId());
186→            } else if (!Objects.equals(targetSpaceNode.getSpaceId(), task.getTargetSpaceId())) {
187→                log.warn("[lbl][2263-mirror-copy][Migration][VALIDATE] targetParentNodeId={} 不属于目标空间站 targetSpaceId={}，实际 spaceId={}，使用根目录",
188→                        task.getTargetParentNodeId(), task.getTargetSpaceId(), targetSpaceNode.getSpaceId());
189→            } else if (!Objects.equals(targetSpaceNode.getType(), SpaceNodeTypeEnum.FOLDER.getValue())) {
190→                log.warn("[lbl][2263-mirror-copy][Migration][VALIDATE] targetParentNodeId={} 不是文件夹类型 type={}，使用根目录",
191→                        task.getTargetParentNodeId(), targetSpaceNode.getType());
192→            } else {
193→                NodeEntity parentNode = nodeService.getByRelId(task.getTargetParentNodeId());
194→                if (parentNode != null) {
195→                    rootParentId = parentNode.getId();
196→                } else {
197→                    log.warn("[lbl][2263-mirror-copy][Migration][VALIDATE] targetParentNodeId={} 对应的 node 不存在，使用根目录", task.getTargetParentNodeId());
198→                }
199→            }
200→        }
201→        saveNewNodeTree(spaceNodeTree, task.getTargetSpaceId(), overallResult.getNodeIdMapping(), userId,
202→                task.getSourceSpaceId(), migrationType, migrationConfig, rootParentId);
203→        // 判断是空间站内迁移并且保留状态是false，调用文件删除接口，把源文件删除
204→        if (!task.getIsRemained() && task.getType().equals(MigrationTypeEnum.INTRA_SERVER.getValue())) {
205→            log.info("[lbl][2122-文件迁移][Migration][DELETE] 移动模式, 开始清理源文件及快照, taskId={}, sourceSpaceId={}, nodeCount={}",
206→                    task.getTaskId(), task.getSourceSpaceId(), spaceNodeTree.size());
207→            for (TreeNode<SpaceNodeVo> treeNode : spaceNodeTree) {
208→                // 清理源文件的版本快照
209→                versionSnapshotService.disableByNodeId(treeNode.getRelId());
210→                spaceNodeUpdateManager.deleteSpaceNode(treeNode.getRelId(), userId);
211→            }
212→        }
213→    }
