215→    private void saveNewNodeTree(List<TreeNode<SpaceNodeVo>> originalTree, String spaceId, Map<String, String> nodeIdMapping,
216→                                  Long userId, String sourceSpaceId, MigrationTypeEnum migrationType, MigrationConfig migrationConfig, Long rootParentId) {
217→        if (originalTree == null || originalTree.isEmpty()) {
218→            log.info("No tree nodes to save for space: {}", spaceId);
219→            return;
220→        }
221→
222→        log.info("Starting to save new node tree for space: {}, rootParentId: {}, total original nodes: {}", spaceId, rootParentId, originalTree.size());
223→
224→        for (TreeNode<SpaceNodeVo> node : originalTree) {
225→            saveNodeAndChildren(node, spaceId, nodeIdMapping, rootParentId, userId,
226→                    sourceSpaceId, migrationType, migrationConfig);
227→        }
228→
229→        log.info("Completed saving new node tree for space: {}", spaceId);
230→    }
231→
232→    private String resolveUniqueName(String spaceId, String name, Long parentId) {
233→        if (spaceNodeQueryManager.checkNameWithParentOnly(spaceId, name, parentId)) {
234→            return name;
235→        }
236→        int count = 1;
237→        while (true) {
238→            String candidate = name + "(" + count + ")";
239→            if (spaceNodeQueryManager.checkNameWithParentOnly(spaceId, candidate, parentId)) {
240→                return candidate;
241→            }
242→            count++;
243→        }
244→    }
245→
246→    private void saveNodeAndChildren(TreeNode<SpaceNodeVo> node, String spaceId, Map<String, String> nodeIdMapping,
247→                                      Long parentId, Long userId, String sourceSpaceId,
248→                                      MigrationTypeEnum migrationType, MigrationConfig migrationConfig) {
249→        SpaceNodeVo spaceNodeVo = node.getData();
250→        String oldNodeId = spaceNodeVo.getAppSpaceNodeId();
251→        String newNodeId = nodeIdMapping.get(oldNodeId);
252→
253→        if (Objects.equals(spaceNodeVo.getType(), SpaceNodeTypeEnum.FOLDER.getValue())) {
254→            newNodeId = "";
255→        }
256→
257→        if (newNodeId == null) {
258→            log.error("No mapping found for node: {}", oldNodeId);
259→            return;
260→        }
261→
262→        String originalName = spaceNodeVo.getName();
263→        String name = MigrationTypeEnum.CROSS_SERVER.equals(migrationType)
264→                ? resolveUniqueName(spaceId, originalName, parentId)
265→                : originalName;
266→        if (!name.equals(originalName)) {
267→            log.info("[2010-change-filename] migrate node name conflict, renamed: [{}] -> [{}], spaceId: {}, " +
268→                            "parentId: {}",
269→                    originalName,
270→                    name, spaceId, parentId);
271→        }
272→
273→        SpaceNodeEntity spaceNodeEntity = SpaceNodeEntity.builder()
274→                .appSpaceNodeId(newNodeId)
275→                .name(name)
276→                .type(spaceNodeVo.getType())
277→                .description(spaceNodeVo.getDescription())
278→                .spaceId(spaceId)
279→                .createdBy(userId)
280→                .updatedBy(userId)
281→                .build();
282→
283→        spaceNodeService.save(spaceNodeEntity);
284→        NodeEntity nodeEntity = treeNodeTemplate.addNode(parentId, spaceId, spaceNodeEntity.getId(), SpaceNodeEntity.class);
285→        log.info("migrate node, id: {}, appSpaceNodeId: {}, name: {}, parentId",spaceNodeEntity.getId(),spaceNodeEntity.getAppSpaceNodeId(),spaceNodeEntity.getName());
286→
287→        // 复制文件关联的版本快照
288→        versionSnapshotMigrationHelper.copyVersionSnapshots(node.getRelId(), spaceNodeEntity, spaceId, sourceSpaceId, migrationType, migrationConfig, userId);
289→
290→        if (node.getChildren() != null && !node.getChildren().isEmpty()) {
291→            for (TreeNode<SpaceNodeVo> child : node.getChildren()) {
292→                saveNodeAndChildren(child, spaceId, nodeIdMapping, nodeEntity.getId(), userId,
293→                        sourceSpaceId, migrationType, migrationConfig);
294→            }
295→        }
296→    }
297→
298→
299→    private List<TreeNode<SpaceNodeVo>> deserializeTree(String json) throws IOException {
300→        ObjectMapper mapper = objectMapper.copy();
301→        mapper.addMixIn(TreeNode.class, TreeNodeMixin.class);
302→        SimpleModule module = new SimpleModule();
303→        module.addAbstractTypeMapping(RelIdProvider.class, SpaceNodeVo.class);
304→        mapper.registerModule(module);
305→        JavaType treeNodeType =
306→                mapper.getTypeFactory().constructParametricType(TreeNode.class, SpaceNodeVo.class);
307→        JavaType listType =
308→                mapper.getTypeFactory().constructCollectionType(List.class, treeNodeType);
309→        return mapper.readValue(json, listType);
310→    }
311→
312→}

