package com.yottastudios.ns.collabspace.user.consumer;

import cn.hutool.json.JSONUtil;
import com.rabbitmq.client.Channel;
import com.yottastudios.ns.collabspace.grpc.IApitableGrpcClientService;
import com.yottastudios.ns.collabspace.user.dto.UserTeamOperateMessage;
import com.yottastudios.ns.collabspace.user.entity.UserTeamAppRelEntity;
import com.yottastudios.ns.collabspace.user.entity.UserTeamUserRelEntity;
import com.yottastudios.ns.collabspace.user.service.IUserTeamAppRelService;
import com.yottastudios.ns.collabspace.user.service.IUserTeamUserRelService;
import jakarta.annotation.Resource;
import lombok.extern.slf4j.Slf4j;
import org.apache.commons.collections4.CollectionUtils;
import org.springframework.amqp.core.Message;
import org.springframework.amqp.rabbit.annotation.RabbitListener;
import org.springframework.stereotype.Component;
import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty;

import java.io.IOException;
import java.util.List;

import static com.yottastudios.ns.collabspace.shared.config.QueueConfig.AIO_TEAM_OPERATE_QUEUE;

/**
 * 自动编排
 */

@Slf4j
@Component
@ConditionalOnProperty(name = "mq.enabled", havingValue = "true", matchIfMissing = true)
public class UserTeamOperateConsumer {

    @Resource
    private IUserTeamAppRelService userTeamAppRelService;

    @Resource
    private IApitableGrpcClientService apitableGrpcClientService;

    @Resource
    private IUserTeamUserRelService userTeamUserRelService;


    @RabbitListener(queues = AIO_TEAM_OPERATE_QUEUE)
    public void handle(Message message, Channel channel) throws IOException {
        long deliveryTag = message.getMessageProperties().getDeliveryTag();
        try {
            String body = new String(message.getBody());
            log.info("人员小组编辑收到消息: {}", body);

            UserTeamOperateMessage messageDto = JSONUtil.toBean(body, UserTeamOperateMessage.class);

            List<Long> teamIds = messageDto.getTeamIds();
            List<Long> userIds = messageDto.getUserIds();
            String operation = messageDto.getOperation();
            Long operatorId = messageDto.getOperatorId();

            //todo 后期可能根据type扩展

            List<UserTeamAppRelEntity> userTeamAppRelEntities = userTeamAppRelService.listInTeamIds(teamIds);
            if (CollectionUtils.isEmpty(userTeamAppRelEntities)) {
                channel.basicAck(deliveryTag, false);
                return;
            }

            if ("delete_team".equals(operation)) {
                Long teamId = teamIds.getFirst();
                for (UserTeamAppRelEntity userTeamAppRelEntity : userTeamAppRelEntities) {

                    List<UserTeamAppRelEntity> relTeamList = userTeamAppRelService.listByAppTeamIdAndAppSpaceId(userTeamAppRelEntity.getAppTeamId(), userTeamAppRelEntity.getAppSpaceId());
                    List<Long> otherTeamIds = relTeamList.stream().filter(x -> !x.getTeamId().equals(teamId)).toList().stream().map(UserTeamAppRelEntity::getTeamId).toList();
                    if (CollectionUtils.isNotEmpty(otherTeamIds)) {
                        List<UserTeamUserRelEntity> otherTeamUsers = userTeamUserRelService.listInTeamIds(otherTeamIds);
                        if (CollectionUtils.isNotEmpty(otherTeamUsers)) {
                            List<Long> otherTeamUserIds = otherTeamUsers.stream().map(UserTeamUserRelEntity::getUserId).toList();
                            userIds = userIds.stream().filter(x -> !otherTeamUserIds.contains(x)).toList();
                        }
                    }

                    apitableGrpcClientService.removeUsersFromTeam(userTeamAppRelEntity.getAppSpaceId(),
                            userIds, Long.valueOf(userTeamAppRelEntity.getAppTeamId()),operatorId,true);
                }
            } else if ("delete_user".equals(operation)) {
                for (UserTeamAppRelEntity userTeamAppRelEntity : userTeamAppRelEntities) {
                    apitableGrpcClientService.removeUsersFromTeam(userTeamAppRelEntity.getAppSpaceId(),
                            userIds, Long.valueOf(userTeamAppRelEntity.getAppTeamId()),operatorId,true);
                }
            } else if ("add_user".equals(operation)) {
                for (UserTeamAppRelEntity userTeamAppRelEntity : userTeamAppRelEntities) {
                    apitableGrpcClientService.addUsersToTeam(userTeamAppRelEntity.getAppSpaceId(),
                            userIds, Long.valueOf(userTeamAppRelEntity.getAppTeamId()),true);
                }
            }
            channel.basicAck(deliveryTag, false);
        } catch (Exception e) {
            log.error("人员小组编辑消费Error:{}", e.getMessage());
            channel.basicNack(deliveryTag, false, false);
        }


    }

}

