import lombok.extern.slf4j.Slf4j;
import org.springframework.amqp.AmqpException;
import org.springframework.amqp.core.Message;
import org.springframework.amqp.rabbit.annotation.RabbitListener;
import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty;
import org.springframework.stereotype.Component;

import java.io.IOException;

import static com.yottastudios.ns.collabspace.shared.config.QueueConfig.THIRD_APP_UPLOAD_UPDATE_QUEUE;

@Slf4j
@Component
@ConditionalOnProperty(name = "mq.enabled", havingValue = "true", matchIfMissing = true)
public class ThirdAppUploadUpdateConsumer {

    @Resource(name = "defaultAppUploadDataServiceImpl")
    private DefaultAppUploadDataServiceImpl defaultAppUploadDataService;

    @RabbitListener(queues = THIRD_APP_UPLOAD_UPDATE_QUEUE)
    public void handle(Message message, Channel channel) throws IOException {
        long deliveryTag = message.getMessageProperties().getDeliveryTag();
        String body = new String(message.getBody());
        log.info("收到 uploadUpdateTime MQ 消息: {}", body);
        try {
            defaultAppUploadDataService.doUploadUpdateTime(body);
            channel.basicAck(deliveryTag, false);
        } catch (AmqpException e) {
            // Channel 已关闭，无法 ack/nack，让 Spring AMQP 框架处理重连
            log.error("[lbl][2417-MQ消费ACK-fixbug][ThirdAppUpload][ACK] Channel已关闭, 无法确认消息, body={}", body, e);
            throw e;
        } catch (Exception e) {
            log.error("[lbl][2417-MQ消费ACK-fixbug][ThirdAppUpload][CONSUME] 消费失败, body={}", body, e);
            try {
                channel.basicNack(deliveryTag, false, false); // requeue=false，避免无限重试
            } catch (Exception nackEx) {
                log.warn("[lbl][2417-MQ消费ACK-fixbug][ThirdAppUpload][NACK] basicNack也失败, Channel可能已关闭", nackEx);
            }
            throw e;
        }
    }
}

