 26→ */
 27→
 28→@Slf4j
 29→@Component
 30→@ConditionalOnProperty(name = "mq.enabled", havingValue = "true", matchIfMissing = true)
 31→public class UserTeamOperateConsumer {
 32→
 33→    @Resource
 34→    private IUserTeamAppRelService userTeamAppRelService;
 35→
 36→    @Resource
 37→    private IApitableGrpcClientService apitableGrpcClientService;
 38→
 39→    @Resource
 40→    private IUserTeamUserRelService userTeamUserRelService;
 41→
 42→
 43→    @RabbitListener(queues = AIO_TEAM_OPERATE_QUEUE)
 44→    public void handle(Message message, Channel channel) throws IOException {
 45→        long deliveryTag = message.getMessageProperties().getDeliveryTag();
 46→        try {
 47→            String body = new String(message.getBody());
 48→            log.info("人员小组编辑收到消息: {}", body);
 49→
 50→            UserTeamOperateMessage messageDto = JSONUtil.toBean(body, UserTeamOperateMessage.class);
 51→
 52→            List<Long> teamIds = messageDto.getTeamIds();
 53→            List<Long> userIds = messageDto.getUserIds();
 54→            String operation = messageDto.getOperation();
 55→            Long operatorId = messageDto.getOperatorId();
 56→
 57→            //todo 后期可能根据type扩展
 58→
 59→            List<UserTeamAppRelEntity> userTeamAppRelEntities = userTeamAppRelService.listInTeamIds(teamIds);
 60→            if (CollectionUtils.isEmpty(userTeamAppRelEntities)) {
 61→                channel.basicAck(deliveryTag, false);
 62→                return;
 63→            }
 64→
 65→            if ("delete_team".equals(operation)) {
 66→                Long teamId = teamIds.getFirst();
 67→                for (UserTeamAppRelEntity userTeamAppRelEntity : userTeamAppRelEntities) {
 68→
 69→                    List<UserTeamAppRelEntity> relTeamList = userTeamAppRelService.listByAppTeamIdAndAppSpaceId(userTeamAppRelEntity.getAppTeamId(), userTeamAppRelEntity.getAppSpaceId());
 70→                    List<Long> otherTeamIds = relTeamList.stream().filter(x -> !x.getTeamId().equals(teamId)).toList().stream().map(UserTeamAppRelEntity::getTeamId).toList();
 71→                    if (CollectionUtils.isNotEmpty(otherTeamIds)) {
 72→                        List<UserTeamUserRelEntity> otherTeamUsers = userTeamUserRelService.listInTeamIds(otherTeamIds);
 73→                        if (CollectionUtils.isNotEmpty(otherTeamUsers)) {
 74→                            List<Long> otherTeamUserIds = otherTeamUsers.stream().map(UserTeamUserRelEntity::getUserId).toList();
 75→                            userIds = userIds.stream().filter(x -> !otherTeamUserIds.contains(x)).toList();
 76→                        }
 77→                    }
