 79→                    apitableGrpcClientService.removeUsersFromTeam(userTeamAppRelEntity.getAppSpaceId(),
 80→                            userIds, Long.valueOf(userTeamAppRelEntity.getAppTeamId()),operatorId,true);
 81→                }
 82→            } else if ("delete_user".equals(operation)) {
 83→                for (UserTeamAppRelEntity userTeamAppRelEntity : userTeamAppRelEntities) {
 84→                    apitableGrpcClientService.removeUsersFromTeam(userTeamAppRelEntity.getAppSpaceId(),
 85→                            userIds, Long.valueOf(userTeamAppRelEntity.getAppTeamId()),operatorId,true);
 86→                }
